-- One-time migration: seeds vehicle_signals with the 40 vehicles from
-- "test data/2hire vehicle test data.json" (identical to
-- src/data/mock/2hireVehicleData.json, the data actually used while
-- VITE_DATA_SOURCE=mockup-data). Confirmed against the live schema before
-- writing this — column names matched vehicle_signals_table.sql exactly, no
-- drift this time.
--
-- Field mapping (source JSON -> vehicle_signals column):
--   vehicleId                    -> vehicle_id                     (uuid)
--   online                      -> online                         ("TRUE"/"FALSE" -> boolean)
--   onlineUpdatedAt              -> online_updated_at               ("DD/MM/YYYY HH.MM" -> timestamptz)
--   autonomyPercentage           -> autonomy_percentage             ("30%" -> numeric 30; 2 vehicles have no value -> null)
--   autonomyPercentageUpdatedAt  -> autonomy_percentage_updated_at
--   distanceCovered              -> distance_covered_meters        ("298,409 km" -> 298409 km -> *1000 -> 298409000 meters)
--   distanceCoveredUpdatedAt     -> distance_covered_updated_at
--
-- lat/lng sourced from src/data/mock/2hireGPSData.json (matched by
-- vehicleId — all 40 vehicles have a matching GPS entry, confirmed before
-- writing this). position_updated_at is set to the same value as
-- distance_covered_updated_at, per explicit instruction (this GPS fixture
-- data has no timestamp of its own to use instead).
--
-- Safe to re-run: upserts on vehicle_id (do update) rather than failing on
-- a second run. Requires vehicle_profiles to already contain matching
-- vehicle_id rows first (see seed_vehicle_profiles.sql) — vehicle_signals
-- has a foreign key to vehicle_profiles.vehicle_id.

on conflict (vehicle_id) do update set
  online = excluded.online,
  online_updated_at = excluded.online_updated_at,
  autonomy_percentage = excluded.autonomy_percentage,
  autonomy_percentage_updated_at = excluded.autonomy_percentage_updated_at,
  distance_covered_meters = excluded.distance_covered_meters,
  distance_covered_updated_at = excluded.distance_covered_updated_at,
  lat = excluded.lat,
  lng = excluded.lng,
  position_updated_at = excluded.position_updated_at;
